import os
import requests
import hashlib
import hmac
import time
from typing import Dict, Any

class BinanceAPI:
    """A secure and flexible wrapper for Binance API."""

    def __init__(self):
        self.base_url = "https://api.binance.com"
        self.api_key = os.getenv('BINANCE_API_KEY')
        self.secret_key = os.getenv('BINANCE_SECRET_KEY')
        self._validate_keys()

    def _validate_keys(self):
        """Validate the API and secret keys."""
        if not self.api_key or not self.secret_key:
            raise ValueError('The API and secret keys must be set in the environment variables.')

    def _get_signature(self, params: Dict[str, Any]) -> str:
        """Generate the signature for the request."""
        query_string = '&'.join([f"{k}={v}" for k, v in params.items()])
        return hmac.new(self.secret_key.encode('utf-8'), query_string.encode('utf-8'), hashlib.sha256).hexdigest()

    def _send_get_request(self, endpoint: str, params: Dict[str, Any] = None):
        """Send a GET request to the Binance API."""
        return self._send_request(requests.get, endpoint, params)

    def _send_post_request(self, endpoint: str, params: Dict[str, Any] = None):
        """Send a POST request to the Binance API."""
        return self._send_request(requests.post, endpoint, params)

    def _send_request(self, request_method, endpoint: str, params: Dict[str, Any] = None):
        """Send a request to the Binance API."""
        headers = {'X-MBX-APIKEY': self.api_key}
        url = f"{self.base_url}{endpoint}"
        params = params or {}
        response = request_method(url, headers=headers, data=params)

        if response.status_code != 200:
            raise ValueError(f"Request error: {response.text}")

        return response.json()

    def get_ticker_price(self, symbol: str) -> float:
        """Get the latest price for a symbol."""
        params = {'symbol': symbol}
        data = self._send_get_request("/api/v3/ticker/price", params)
        return float(data['price'])

    def place_order(self, symbol: str, side: str, quantity: float, order_type: str = "MARKET", price: float = None, timeInForce: str = None):
        """Place an order."""
        assert side in ["BUY", "SELL"], "Invalid order side"
        assert order_type in ["LIMIT", "MARKET", "STOP_LOSS", "STOP_LOSS_LIMIT", "TAKE_PROFIT", "TAKE_PROFIT_LIMIT", "LIMIT_MAKER"], "Invalid order type"
        timestamp = int(time.time() * 1000)
        params = {
            'symbol': symbol,
            'side': side,
            'type': order_type,
            'quantity': quantity,
            'timestamp': timestamp
        }
        if price is not None:
            params['price'] = price
        if timeInForce is not None:
            params['timeInForce'] = timeInForce
        params['signature'] = self._get_signature(params)
        return self._send_post_request("/api/v3/order", params)

import os
