        """
        Sign the provided parameters using the secret key.
        """
        query_string = '&'.join([f"{key}={value}" for key, value in params.items()])
        signature = hmac.new(self.secret_key.encode(), query_string.encode(), digestmod='sha256').hexdigest()
        return signature

    def get_server_time(self) -> Dict[str, Any]:
        """
        Get the server time from the Binance API.
        """
        url = self.BASE_URL + "/api/v3/time"
        try:
